import React from 'react';
import { Card, Stack, Text, Heading, Divider } from '@ggui-ai/design/primitives';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city = 'Unknown City',
    temperature = 0,
    condition = 'Clear',
    humidity = 0,
    windSpeed = 0,
    unit = '°C',
    forecast = [],
  } = props;

  return (
    <Card shadow="md" padding={24} radius="lg">
      <Stack gap={16}>
        {/* City and Condition */}
        <Stack gap={4}>
          <Heading level={3}>{city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            {condition}
          </Text>
        </Stack>

        {/* Current Temperature */}
        <Stack align="center" gap={0}>
          <Heading level={1}>
            {temperature}
            {unit}
          </Heading>
        </Stack>

        {/* Metrics */}
        <Stack direction="horizontal" justify="between">
          <Stack gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Humidity
            </Text>
            <Text weight="semibold">{humidity}%</Text>
          </Stack>
          <Stack gap={4} align="end">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Wind
            </Text>
            <Text weight="semibold">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider margin={8} />

        {/* Forecast Strip */}
        <Stack direction="horizontal" justify="between">
          {forecast.map((item, index) => (
            <Stack key={index} align="center" gap={8}>
              <Text variant="caption">{item.day ?? '-'}</Text>
              <Text size="xl">{item.icon ?? '☀️'}</Text>
              <Stack gap={0} align="center">
                <Text variant="bodySmall" weight="semibold">
                  {item.high ?? 0}°
                </Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {item.low ?? 0}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import { Container, Stack, Box, Card, Text, Heading, Input } from '@ggui-ai/design/primitives';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const getCategoryColor = (category?: string) => {
  const map: Record<string, string> = {
    'noble-gas': 'var(--ggui-color-info-200, #a5f3fc)',
    'halogen': 'var(--ggui-color-warning-200, #fde68a)',
    'nonmetal': 'var(--ggui-color-success-200, #bbf7d0)',
    'alkali-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
    'alkaline-earth-metal': 'var(--ggui-color-primary-200, #bae6fd)',
    'transition-metal': 'var(--ggui-color-primary-300, #7dd3fc)',
    'post-transition-metal': 'var(--ggui-color-primary-400, #38bdf8)',
    'metalloid': 'var(--ggui-color-success-300, #86efac)',
    'lanthanide': 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    'actinide': 'var(--ggui-color-surfaceVariant, #f4f4f5)',
  };
  return map[category ?? ''] ?? 'var(--ggui-color-surfaceVariant, #f4f4f5)';
};

export default function GeneratedComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  const filteredElements = props.elements.filter(
    (el) =>
      el.name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      el.symbol?.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-8, 32px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack gap="var(--ggui-spacing-4, 16px)" align="center">
          <Heading level={1}>Periodic Table</Heading>
          <Box style={{ width: '320px' }}>
            <Input
              label="Search elements"
              placeholder="Search by name or symbol..."
              value={searchQuery}
              onChange={setSearchQuery}
            />
          </Box>
        </Stack>

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1, 4px)',
          }}
        >
          {props.elements.map((el, i) => {
            const isMatch = searchQuery === '' || filteredElements.includes(el);
            return (
              <Box
                key={`${el.atomicNumber ?? i}`}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  backgroundColor: isMatch
                    ? getCategoryColor(el.category)
                    : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  padding: 'var(--ggui-spacing-2, 8px)',
                  opacity: isMatch ? 1 : 0.2,
                  minHeight: '64px',
                  display: 'flex',
                  flexDirection: 'column',
                  transition: 'opacity 200ms ease',
                }}
              >
                <button
                  type="button"
                  aria-label={`${el.name ?? 'Unknown'}, ${el.symbol ?? ''}`}
                  onClick={() => isMatch && setSelectedElement(el)}
                  style={{
                    background: 'none',
                    border: 'none',
                    padding: 0,
                    width: '100%',
                    height: '100%',
                    textAlign: 'left',
                    cursor: isMatch ? 'pointer' : 'default',
                  }}
                >
                  <Text size="xs">{el.atomicNumber}</Text>
                  <Text weight="bold" size="2xl" align="center">
                    {el.symbol}
                  </Text>
                </button>
              </Box>
            );
          })}
        </Box>

        {selectedElement && (
          <Card padding="var(--ggui-spacing-6, 24px)" radius="lg">
            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Heading level={3}>{selectedElement.name}</Heading>
              <Text variant="bodyLarge">Symbol: {selectedElement.symbol}</Text>
              <Text variant="body">Atomic Number: {selectedElement.atomicNumber}</Text>
              <Text variant="body">Atomic Weight: {selectedElement.atomicWeight}</Text>
              <Text variant="body">Category: {selectedElement.category}</Text>
            </Stack>
          </Card>
        )}

        <Card padding="var(--ggui-spacing-6, 24px)">
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Heading level={4}>Legend</Heading>
            <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
              {['noble-gas', 'halogen', 'nonmetal', 'alkali-metal', 'transition-metal', 'metalloid'].map((cat) => (
                <Stack key={cat} direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
                  <Box
                    style={{
                      width: 16,
                      height: 16,
                      background: getCategoryColor(cat),
                      borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    }}
                  />
                  <Text variant="label">{cat.replace('-', ' ')}</Text>
                </Stack>
              ))}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Divider,
  Spacer,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Toggle,
  RadioGroup,
  Progress,
} from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name ?? '',
    email: props.initialProfile?.email ?? '',
    avatar: props.initialProfile?.avatar ?? (props.avatarOptions[0] ?? ''),
    role: props.initialProfile?.role ?? (props.roleOptions[0] ?? ''),
    emailNotifications: props.initialProfile?.emailNotifications ?? false,
    theme: props.initialProfile?.theme ?? 'light',
  });

  useEffect(() => {
    const handleAgentData = (e: any) => {
      console.log('Agent Data Received:', e.detail);
    };
    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
  }, []);

  const validateEmail = (email: string) => /\S+@\S+\.\S+/.test(email);

  const isStep1Valid = useMemo(() => 
    formData.name.trim().length > 0 && validateEmail(formData.email), 
    [formData.name, formData.email]
  );

  const handleNext = () => setStep((s) => Math.min(s + 1, 3));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));
  const handleSubmit = () => props.onComplete?.(formData);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Box>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Step {step} of 3</Text>
          <Progress value={(step / 3) * 100} size="md" />
        </Box>

        <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" border={true}>
          <Stack gap="var(--ggui-spacing-6, 24px)">
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Heading level={3}>Profile Setup</Heading>
                <Input 
                  label="Name" 
                  value={formData.name} 
                  onChange={(v) => setFormData(p => ({ ...p, name: v }))} 
                  required 
                />
                <Input 
                  label="Email" 
                  type="email" 
                  value={formData.email} 
                  onChange={(v) => setFormData(p => ({ ...p, email: v }))} 
                  required 
                  error={formData.email && !validateEmail(formData.email) ? 'Invalid email format' : undefined} 
                />
                <RadioGroup 
                  label="Avatar" 
                  value={formData.avatar} 
                  onChange={(v) => setFormData(p => ({ ...p, avatar: v }))} 
                  options={props.avatarOptions.map(o => ({ value: o, label: o }))} 
                  direction="horizontal" 
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Heading level={3}>Preferences</Heading>
                <Select 
                  label="Role" 
                  value={formData.role} 
                  onChange={(v) => setFormData(p => ({ ...p, role: v }))} 
                  options={props.roleOptions.map(o => ({ value: o, label: o }))} 
                />
                <Toggle 
                  label="Email Notifications" 
                  checked={formData.emailNotifications} 
                  onChange={(v) => setFormData(p => ({ ...p, emailNotifications: v }))} 
                />
                <Select 
                  label="Theme" 
                  value={formData.theme} 
                  onChange={(v) => setFormData(p => ({ ...p, theme: v }))} 
                  options={[{ value: 'light', label: 'Light' }, { value: 'dark', label: 'Dark' }]} 
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Heading level={3}>Review & Confirm</Heading>
                <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding="var(--ggui-spacing-4, 16px)" borderRadius="var(--ggui-shape-radius-md, 8px)">
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Text><strong>Name:</strong> {formData.name}</Text>
                    <Text><strong>Email:</strong> {formData.email}</Text>
                    <Text><strong>Role:</strong> {formData.role}</Text>
                    <Text><strong>Avatar:</strong> {formData.avatar}</Text>
                    <Text><strong>Notifications:</strong> {formData.emailNotifications ? 'On' : 'Off'}</Text>
                    <Text><strong>Theme:</strong> {formData.theme}</Text>
                  </Stack>
                </Box>
              </Stack>
            )}

            <Divider />

            <Stack direction="horizontal" justify="between">
              <Button 
                variant="ghost" 
                onClick={handleBack} 
                disabled={step === 1}
              >
                Go Back
              </Button>
              {step < 3 ? (
                <Button 
                  variant="primary" 
                  onClick={handleNext} 
                  disabled={step === 1 && !isStep1Valid}
                >
                  Next
                </Button>
              ) : (
                <Button 
                  variant="primary" 
                  onClick={handleSubmit}
                >
                  Complete Setup
                </Button>
              )}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

