// --- hooks.ts ---
// Path: /virtual/hooks.ts
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useMemo } from 'react';

export function useComponent(props: Props): HookReturn {
  const {
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast,
  } = props;

  return useMemo(() => {
    const icons: Record<string, string> = {
      Sunny: '☀️',
      Rainy: '🌧️',
      Cloudy: '☁️',
      Snowy: '❄️',
    };

    return {
      formattedTemp: `${Math.round(temperature)}°`,
      formattedUnit: unit === 'F' ? '°F' : '°C',
      conditionIcon: icons[condition] || '🌡️',
      forecastData: forecast,
      details: {
        humidity: `${humidity}%`,
        wind: `${windSpeed} ${unit === 'F' ? 'mph' : 'km/h'}`,
      },
    };
  }, [temperature, condition, humidity, windSpeed, unit, forecast]);
}


