  return (
    <Stack
      direction="horizontal"
      justify="around"
      align="center"
      gap="var(--ggui-spacing-4, 16px)"
      style={{
        borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
        padding: 'var(--ggui-spacing-4, 16px) 0',
        width: '100%',
      }}
    >
      {/* Humidity Metric Block */}
      <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
        <Icon 
          name="water_drop" 
          size={24} 
          color="var(--ggui-color-onSurfaceVariant, #52525b)" 
        />
        <Stack gap={0}>
          <Text 
            variant="caption" 
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            Humidity
          </Text>
          <Text 
            variant="bodyLarge" 
            weight="bold" 
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {humidity}%
          </Text>
        </Stack>
      </Stack>

      {/* Wind Speed Metric Block */}
      <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
        <Icon 
          name="air" 
          size={24} 
          color="var(--ggui-color-onSurfaceVariant, #52525b)" 
        />
        <Stack gap={0}>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Wind Speed
          </Text>
          <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
            {windSpeed} km/h
          </Text>
        </Stack>
      </Stack>
    </Stack>
  );
};

