// Path: /virtual/hooks.ts
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

export function useComponent(props: Props): HookReturn {

  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<PeriodicElement | null>(null);

  const categories = useMemo(() => {
    const uniqueCategories = new Set(props.elements.map((el) => el.category));
    return Array.from(uniqueCategories);
  }, [props.elements]);

  const filteredElements = useMemo(() => {
    const query = searchQuery.toLowerCase().trim();
    if (!query) {
      return props.elements;
    }
    return props.elements.filter(
      (el) =>
        el.name.toLowerCase().includes(query) ||
        el.symbol.toLowerCase().includes(query)
    );
  }, [props.elements, searchQuery]);

  const handleSelectElement = (element: PeriodicElement) => {
    setSelectedElement(element);
  };

  return {
    searchQuery,
    setSearchQuery,
    selectedElement,
    handleSelectElement,
    filteredElements,
    categories,
  };
}


