import React from 'react';
import { Box, Text } from '@ggui-ai/design/primitives';
import { ElementCellProps } from '/virtual/types';

const CATEGORY_COLORS: Record<string, string> = {
  'alkali-metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'alkaline-earth-metal': 'var(--ggui-color-warning-200, #fde68a)',
  'transition-metal': 'var(--ggui-color-surfaceVariant, #f4f4f5)',
  'post-transition-metal': 'var(--ggui-color-outlineVariant, #e4e4e7)',
  'metalloid': 'var(--ggui-color-success-100, #dcfce7)',
  'polyatomic-nonmetal': 'var(--ggui-color-primary-50, #f0f9ff)',
  'diatomic-nonmetal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'noble-gas': 'var(--ggui-color-primary-200, #bae6fd)',
  'lanthanide': 'var(--ggui-color-info-100, #cffafe)',
  'actinide': 'var(--ggui-color-error-100, #fee2e2)',
};

/**
 * ElementCell component represents an individual element in the periodic table.
 * It uses CSS Grid for positioning and applies semantic coloring based on the element's category.
 */
export const ElementCell: React.FC<ElementCellProps> = ({
  element,
  isSelected,
  isDimmed,
  onClick,
}) => {
  const [isHovered, setIsHovered] = React.useState(false);

  const categoryColor = CATEGORY_COLORS[element.category] || 'var(--ggui-color-surface, #fafafa)';

  // Root Box styles according to instructions
  const cellStyle: React.CSSProperties = {
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
    gridRow: element.row,
    gridColumn: element.col,
    aspectRatio: '1/1',
    cursor: 'pointer',
    userSelect: 'none',
    position: 'relative',
    transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
    border: isSelected 
      ? '2px solid var(--ggui-color-primary-500, #0ea5e9)' 
      : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
    transform: isSelected ? 'scale(1.05)' : (isHovered ? 'scale(1.02)' : 'scale(1)'),
    zIndex: isSelected ? 10 : (isHovered ? 5 : 1),
    opacity: isDimmed ? 0.3 : 1,
    filter: isDimmed ? 'grayscale(80%)' : 'none',
    boxShadow: isHovered || isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
    overflow: 'hidden',
  };

  return (
    <Box
      background={isHovered ? 'var(--ggui-color-surface, #ffffff)' : categoryColor}
      borderRadius="var(--ggui-shape-radius-md, 8px)"
      padding="var(--ggui-spacing-1, 4px)"
      // Passing style for grid layout and dynamic visual states
      // @ts-ignore
      style={cellStyle}
      // Explicitly requested to attach onClick to the root Box
      // @ts-ignore
      onClick={() => onClick(element)}
      // Hover states handled via mouse events to update background/scale smoothly
      // @ts-ignore
      onMouseEnter={() => setIsHovered(true)}
      // @ts-ignore
      onMouseLeave={() => setIsHovered(false)}
    >
      {/* Atomic Number in Top-Left */}
      <div style={{ position: 'absolute', top: '2px', left: '4px', pointerEvents: 'none' }}>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {element.atomicNumber}
        </Text>
      </div>

      {/* Element Symbol in Center */}
      <Text 
        variant="bodyLarge" 
        weight="bold" 
        color="var(--ggui-color-onSurface, #18181b)"
        align="center"
      >
        {element.symbol}
      </Text>

      {/* Element Name at Bottom */}
      <div style={{ position: 'absolute', bottom: '2px', left: '4px', right: '4px', pointerEvents: 'none' }}>
        <Text 
          variant="caption" 
          truncate
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
          align="center"
        >
          {element.name}
        </Text>
      </div>
    </Box>
  );
};

