/**
 * Helper to map periodic element categories to design system Badge variants.
 */
const getCategoryVariant = (category: string): 'default' | 'primary' | 'secondary' | 'success' | 'warning' | 'error' | 'info' => {
  const map: Record<string, 'default' | 'primary' | 'secondary' | 'success' | 'warning' | 'error' | 'info'> = {
    'noble-gas': 'info',
    'alkali-metal': 'error',
    'alkaline-earth-metal': 'warning',
    'transition-metal': 'primary',
    'post-transition-metal': 'success',
    'metalloid': 'secondary',
    'diatomic-nonmetal': 'default',
    'polyatomic-nonmetal': 'default',
    'lanthanide': 'info',
    'actinide': 'error',
  };
  return map[category] || 'default';
};

/**
 * Helper to map category strings to background colors for UI accents.
 */
const getCategoryColor = (category: string): string => {
  const map: Record<string, string> = {
    'noble-gas': 'var(--ggui-color-info-100, #cffafe)',
    'alkali-metal': 'var(--ggui-color-error-100, #fee2e2)',
    'alkaline-earth-metal': 'var(--ggui-color-warning-100, #fef3c7)',
    'transition-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
    'post-transition-metal': 'var(--ggui-color-success-100, #dcfce7)',
    'metalloid': 'var(--ggui-color-outlineVariant, #e4e4e7)',
  };
  return map[category] || 'var(--ggui-color-surfaceVariant, #f4f4f5)';
};

