// Path: /virtual/components/Legend.tsx
import React from 'react';
import { Box, Stack, Text } from '@ggui-ai/design/primitives';
import { LegendProps } from '/virtual/types';

const getCategoryColor = (category: string): string => {
  switch (category.toLowerCase()) {
    case 'alkali-metal': return 'var(--ggui-color-warning, #d97706)';
    case 'alkaline-earth-metal': return 'var(--ggui-color-warning-300, #fcd34d)';
    case 'transition-metal': return 'var(--ggui-color-error, #dc2626)';
    case 'post-transition-metal': return 'var(--ggui-color-primary-400, #38bdf8)';
    case 'metalloid': return 'var(--ggui-color-success-400, #4ade80)';
    case 'reactive-nonmetal': return 'var(--ggui-color-success, #16a34a)';
    case 'noble-gas': return 'var(--ggui-color-info, #0284c7)';
    case 'lanthanide': return 'var(--ggui-color-primary-200, #bae6fd)';
    case 'actinide': return 'var(--ggui-color-primary-700, #0369a1)';
    default: return 'var(--ggui-color-outline, #d4d4d8)';
  }
};

const formatCategory = (category: string): string => {
  return category
    .split('-')
    .map(word => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
};

export const Legend: React.FC<LegendProps> = ({ categories, activeCategory }) => {
  return (
    <Box
      padding="var(--ggui-spacing-4, 16px)"
      borderRadius="var(--ggui-shape-radius-lg, 12px)"
      background="var(--ggui-color-surfaceVariant, #f4f4f5)"
    >
      <Stack gap={12}>
        <Text variant="label" weight="semibold">Legend</Text>
        <Stack direction="horizontal" wrap gap={16}>
          {categories.map((category) => {
            const isDimmed = activeCategory && activeCategory !== category;
            return (
              <Stack
                key={category}
                direction="horizontal"
                align="center"
                gap={8}
                style={{
                  opacity: isDimmed ? 0.4 : 1,
                  transition: 'opacity 200ms ease-in-out',
                }}
              >
                <Box
                  style={{ width: 16, height: 16 }}
                  borderRadius="var(--ggui-shape-radius-sm, 4px)"
                  background={getCategoryColor(category)}
                />
                <Text variant="caption">
                  {formatCategory(category)}
                </Text>
              </Stack>
            );
          })}
        </Stack>
      </Stack>
    </Box>
  );
};

