// Path: /virtual/components/ProgressIndicator.tsx
import React from 'react';
import { Stack, Text, Heading, Progress, Box } from '@ggui-ai/design/primitives';
import { ProgressIndicatorProps } from '/virtual/types';

export const ProgressIndicator: React.FC<ProgressIndicatorProps> = ({
  currentStep,
  totalSteps,
}) => {
  const progressValue = (currentStep / totalSteps) * 100;

  return (
    <Stack gap="var(--ggui-spacing-4)" style={{ paddingBottom: 'var(--ggui-spacing-6)' }}>
      {/* Top Section */}
      <Stack direction="horizontal" justify="between" align="center">
        <Heading level={6}>Step {currentStep}</Heading>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
          {currentStep} of {totalSteps}
        </Text>
      </Stack>

      {/* Progress Bar */}
      <Progress value={progressValue} variant="default" size="sm" />

      {/* Step Visualizer */}
      <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="center" justify="center">
        {Array.from({ length: totalSteps }).map((_, index) => {
          const stepNumber = index + 1;
          const isActive = stepNumber === currentStep;
          const isCompleted = stepNumber < currentStep;

          let bg = 'var(--ggui-color-surfaceVariant)';
          let textColor = 'var(--ggui-color-onSurfaceVariant)';
          let borderStyle = '1px solid var(--ggui-color-outline)';

          if (isActive) {
            bg = 'var(--ggui-color-primary-600)';
            textColor = 'var(--ggui-color-onPrimary, #ffffff)';
            borderStyle = 'none';
          } else if (isCompleted) {
            bg = 'var(--ggui-color-primary-100)';
            textColor = 'var(--ggui-color-primary-900)';
            borderStyle = 'none';
          }

          return (
            <Box
              key={stepNumber}
              background={bg}
              borderRadius="50%"
              style={{
                width: '32px',
                height: '32px',
                border: borderStyle,
                transition: 'background-color 200ms ease-in-out, border-color 200ms ease-in-out',
              }}
            >
              <Stack align="center" justify="center" style={{ width: '100%', height: '100%' }}>
                <Text variant="label" weight="bold" color={textColor}>
                  {stepNumber}
                </Text>
              </Stack>
            </Box>
          );
        })}
      </Stack>
    </Stack>
  );
};

