                  }}
                >
                  <Avatar
                    src={avatar}
                    name={`Avatar ${index + 1}`}
                    size={48}
                    shape="circle"
                  />
                </div>
              );
            })}
          </Stack>
        </Stack>
      </Stack>
    </Stack>
  );
};


