// Path: /virtual/components/NavigationControls.tsx
import React from 'react';
import { Stack, Button, Icon, Divider, Box } from '@ggui-ai/design/primitives';
import { NavigationControlsProps } from '/virtual/types';

export const NavigationControls: React.FC<NavigationControlsProps> = ({
  currentStep,
  totalSteps,
  onNext,
  onBack,
  isNextDisabled,
  nextLabel,
}) => {
  const isLastStep = currentStep === totalSteps;
  const showBack = currentStep > 1;

  return (
    <Box padding="var(--ggui-spacing-6) 0 0 0">
      <Divider margin={0} color="var(--ggui-color-outlineVariant)" />
      <Box padding="var(--ggui-spacing-6) 0 0 0">
        <Stack direction="horizontal" justify="between" align="center">
          {showBack ? (
            <Button variant="secondary" onClick={onBack}>
              Back
            </Button>
          ) : (
            <Box />
          )}

          <Button
            variant="primary"
            onClick={onNext}
            disabled={isNextDisabled}
            rightIcon={
              !isLastStep && !nextLabel ? <Icon name="chevron-right" size={16} /> : undefined
            }
          >
            {nextLabel || (isLastStep ? 'Complete Setup' : 'Next Step')}
          </Button>
        </Stack>
      </Box>
    </Box>
  );
};

