// Path: /virtual/components/index.tsx
// components/index.tsx — main component composing sub-components
import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Divider,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  Avatar,
  Icon,
  MotionKeyframes
} from '@ggui-ai/design/primitives';
import {
  OnboardingWizardProps,
  ProfileData,
  OnboardingStep,
  StepProps,
  ProgressIndicatorProps,
  NavigationControlsProps
} from '/virtual/types';

/**
 * Step 1: Basic Profile Information
 */
function Step1Profile({ formData, updateField, avatarOptions = [] }: StepProps) {
  return (
    <Stack gap="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Input label="Full Name"
          placeholder="Enter your name"
          value={formData.name}
          onChange={(val) => updateField('name', val)}
          required={true}
        />
        <Input label="Email Address"
          type="email"
          placeholder="you@example.com"
          value={formData.email}
          onChange={(val) => updateField('email', val)}
          required={true}
        />
      </Stack>

      <Stack gap="var(--ggui-spacing-2, 8px)">
        <Text variant="label">Select an Avatar</Text>
        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
          {avatarOptions.map((url) => (
            <div
              key={url}
              onClick={() => updateField('avatar', url)}
              style={{
                cursor: 'pointer',
                padding: 'var(--ggui-spacing-1, 4px)',
                borderRadius: 'var(--ggui-shape-radius-full)',
                border: `2px solid ${formData.avatar === url ? 'var(--ggui-color-primary-600, #0284c7)' : 'transparent'}`,
                transition: 'all 0.2s ease'
              }}
            >
              <Avatar src={url} size="lg" name={formData.name || 'User'} />
            </div>
          ))}
        </Stack>
      </Stack>
    </Stack>
  );
}

/**
 * Step 2: User Preferences
 */
function Step2Preferences({ formData, updateField, roleOptions = [] }: StepProps) {
  const roles = useMemo(() => roleOptions.map(r => ({ value: r, label: r })), [roleOptions]);

  return (
    <Stack gap="var(--ggui-spacing-6, 24px)">
      <Select
        label="Your Role"
        options={roles}
        value={formData.role}
        onChange={(val) => updateField('role', val)}
      />
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Toggle
          label="Email Notifications"
          checked={formData.emailNotifications}
          onChange={(checked) => updateField('emailNotifications', checked)}
        />
        <Toggle
          label={formData.theme === 'dark' ? 'Dark Mode' : 'Light Mode'}
          checked={formData.theme === 'dark'}
          onChange={(isDark) => updateField('theme', isDark ? 'dark' : 'light')}
        />
      </Stack>
    </Stack>
  );
}

/**
 * Step 3: Review and Confirm
 */
function Step3Review({ formData }: { formData: ProfileData }) {
  const SummaryItem = ({ label, value }: { label: string, value: string | boolean }) => (
    <Box paddingY="var(--ggui-spacing-2, 8px)">
      <Stack direction="horizontal" justify="between" align="center">
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{label}</Text>
        <Text variant="bodySmall" weight="medium">
          {typeof value === 'boolean' ? (value ? 'Enabled' : 'Disabled') : value}
        </Text>
      </Stack>
    </Box>
  );

  return (
    <Stack gap="var(--ggui-spacing-4, 16px)">
      <Stack align="center" gap="var(--ggui-spacing-2, 8px)">
        <Avatar src={formData.avatar} size="xl" name={formData.name} />
        <Heading level={4}>{formData.name}</Heading>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{formData.email}</Text>
      </Stack>
      <Divider margin="var(--ggui-spacing-4, 16px)" />
      <Stack gap="var(--ggui-spacing-1, 4px)">
        <SummaryItem label="Role" value={formData.role} />
        <SummaryItem label="Notifications" value={formData.emailNotifications} />
        <SummaryItem label="Theme" value={formData.theme} />
      </Stack>
    </Stack>
  );
}

/**
 * Progress Indicator Component
 */
function ProgressIndicator({ currentStep, totalSteps }: ProgressIndicatorProps) {
  return (
    <Stack gap="var(--ggui-spacing-2, 8px)">
      <Progress value={currentStep} max={totalSteps} size="sm" />
      <Stack direction="horizontal" justify="between">
        <Text variant="caption">Step {currentStep} of {totalSteps}</Text>
        <Text variant="caption" weight="medium" color="var(--ggui-color-primary-600, #0284c7)">
          {currentStep === 1 ? 'Personal Info' : currentStep === 2 ? 'Preferences' : 'Review'}
        </Text>
      </Stack>
    </Stack>
  );
}

/**
 * Navigation Controls Component
 */
function NavigationControls({ 
  currentStep, 
  totalSteps, 
  onNext, 
  onBack, 
  isNextDisabled, 
  nextLabel 
}: NavigationControlsProps) {
  return (
    <Stack direction="horizontal" justify="between">
      <Button 
        variant="ghost" 
        onClick={onBack} 
        disabled={currentStep === 1}
        leftIcon={<Icon name="chevron-left" size={16} />}
      >
        Back
      </Button>
      <Button 
        variant="primary" 
        onClick={onNext} 
        disabled={isNextDisabled}
        rightIcon={currentStep < totalSteps ? <Icon name="chevron-right" size={16} /> : <Icon name="check" size={16} />}
      >
        {nextLabel || (currentStep === totalSteps ? 'Complete Setup' : 'Continue')}
      </Button>
    </Stack>
  );
}

export function Component({ 
  initialProfile, 
  avatarOptions = [], 
  roleOptions = [], 
  onComplete 
}: OnboardingWizardProps) {
  const [currentStep, setCurrentStep] = useState<OnboardingStep>(1);
  const [formData, setFormData] = useState<ProfileData>({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || avatarOptions[0] || '',
    role: initialProfile?.role || (roleOptions[0] || 'Developer'),
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light',
  });

  const updateField = <K extends keyof ProfileData>(field: K, value: ProfileData[K]) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const isStepValid = useMemo(() => {
    if (currentStep === 1) {
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      return formData.name.trim().length > 0 && emailRegex.test(formData.email);
    }
    return true; // Step 2 and 3 have defaults or are summaries
  }, [currentStep, formData]);

  const handleNext = () => {
    if (currentStep < 3) {
      setCurrentStep((prev) => (prev + 1) as OnboardingStep);
    } else {
      onComplete(formData);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep((prev) => (prev - 1) as OnboardingStep);
    }
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px)">
      <MotionKeyframes />
      <Card shadow="md" padding="var(--ggui-spacing-8, 32px)" radius="xl">
        <Stack gap="var(--ggui-spacing-8, 32px)">
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Heading level={2} align="center">Set up your profile</Heading>
            <ProgressIndicator currentStep={currentStep} totalSteps={3} />
          </Stack>
          <div style={{ animation: 'ggui-fadeIn 300ms ease-out', minHeight: 'var(--ggui-container-xs, 320px)' }} key={currentStep}>
            {currentStep === 1 && <Step1Profile formData={formData} updateField={updateField} avatarOptions={avatarOptions} />}
            {currentStep === 2 && <Step2Preferences formData={formData} updateField={updateField} roleOptions={roleOptions} />}
            {currentStep === 3 && <Step3Review formData={formData} />}
          </div>
          <Divider margin="0" />
          <NavigationControls 
            currentStep={currentStep}
            totalSteps={3}
            onNext={handleNext}
            onBack={handleBack}
            isNextDisabled={!isStepValid}
            nextLabel={currentStep === 3 ? 'Complete Setup' : 'Continue'}
          />
        </Stack>
      </Card>
    </Container>
  );
}


